using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    internal static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            return new SchoolContext(options);
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>()
            };
            var instructor2 = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };

            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            var dept1 = new Department
            {
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor1.ID
            };
            var dept2 = new Department
            {
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor2.ID
            };

            context.Departments.AddRange(dept1, dept2);
            context.SaveChanges();

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept1.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            var course2 = new Course
            {
                CourseID = 2021,
                Title = "Composition",
                Credits = 3,
                DepartmentID = dept2.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Courses.AddRange(course1, course2);
            context.SaveChanges();

            var student1 = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2010-09-01"),
                Enrollments = new List<Enrollment>()
            };
            var student2 = new Student
            {
                FirstMidName = "Meredith",
                LastName = "Alonso",
                EnrollmentDate = DateTime.Parse("2012-09-01"),
                Enrollments = new List<Enrollment>()
            };
            var student3 = new Student
            {
                FirstMidName = "Arturo",
                LastName = "Anand",
                EnrollmentDate = DateTime.Parse("2013-09-01"),
                Enrollments = new List<Enrollment>()
            };

            context.Students.AddRange(student1, student2, student3);
            context.SaveChanges();

            context.Enrollments.Add(new Enrollment
            {
                StudentID = student1.ID,
                CourseID = course1.CourseID,
                Grade = Grade.A
            });
            context.Enrollments.Add(new Enrollment
            {
                StudentID = student2.ID,
                CourseID = course2.CourseID,
                Grade = Grade.B
            });
            context.SaveChanges();

            // CourseAssignments
            context.CourseAssignments.Add(new CourseAssignment
            {
                CourseID = course1.CourseID,
                InstructorID = instructor1.ID
            });
            context.SaveChanges();
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        [DataRow(10, 1, 5, 2, DisplayName = "10 items, page 1, size 5 => 2 pages")]
        [DataRow(10, 2, 5, 2, DisplayName = "10 items, page 2, size 5 => 2 pages")]
        [DataRow(11, 1, 5, 3, DisplayName = "11 items, page 1, size 5 => 3 pages")]
        [DataRow(1, 1, 10, 1, DisplayName = "1 item, page 1, size 10 => 1 page")]
        [DataRow(0, 1, 10, 0, DisplayName = "0 items => 0 pages")]
        public void Constructor_SetsCorrectTotalPages(int count, int pageIndex, int pageSize, int expectedTotalPages)
        {
            var items = new List<int>();

            var sut = new PaginatedList<int>(items, count, pageIndex, pageSize);

            Assert.AreEqual(expectedTotalPages, sut.TotalPages);
            Assert.AreEqual(pageIndex, sut.PageIndex);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };

            var sut = new PaginatedList<string>(items, 10, 1, 3);

            Assert.AreEqual(3, sut.Count);
            CollectionAssert.AreEqual(items, sut);
        }

        [TestMethod]
        [DataRow(1, 3, false, DisplayName = "First page => no previous")]
        [DataRow(2, 3, true, DisplayName = "Second page => has previous")]
        [DataRow(3, 3, true, DisplayName = "Last page => has previous")]
        public void HasPreviousPage_ReturnsExpected(int pageIndex, int totalPages, bool expected)
        {
            var sut = new PaginatedList<int>(new List<int>(), totalPages * 5, pageIndex, 5);

            Assert.AreEqual(expected, sut.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 3, true, DisplayName = "First page of 3 => has next")]
        [DataRow(2, 3, true, DisplayName = "Middle page of 3 => has next")]
        [DataRow(3, 3, false, DisplayName = "Last page of 3 => no next")]
        [DataRow(1, 1, false, DisplayName = "Only page => no next")]
        public void HasNextPage_ReturnsExpected(int pageIndex, int totalPages, bool expected)
        {
            var sut = new PaginatedList<int>(new List<int>(), totalPages * 5, pageIndex, 5);

            Assert.AreEqual(expected, sut.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result.First());
            Assert.AreEqual(20, result.Last());
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result.First());
        }

        [TestMethod]
        public void Create_LastPartialPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(11, result.First());
            Assert.AreEqual(12, result.Last());
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain queue to avoid cross-test leakage from the static ConcurrentQueue
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            _sut.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Course", "101", EntityOperation.UPDATE, "System");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Course (ID: 101) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Department 'Math' has been created", DisplayName = "CREATE message")]
        [DataRow(EntityOperation.UPDATE, "Department 'Math' has been updated", DisplayName = "UPDATE message")]
        [DataRow(EntityOperation.DELETE, "Department 'Math' has been deleted", DisplayName = "DELETE message")]
        public void SendNotification_OperationTypes_GenerateCorrectMessages(EntityOperation operation, string expectedMessage)
        {
            _sut.SendNotification("Department", "1", "Math", operation, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();

            Assert.AreEqual("A", first.EntityType);
            Assert.AreEqual("B", second.EntityType);
            Assert.AreEqual("C", third.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_AfterReceived_QueueIsEmpty()
        {
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);
            _sut.ReceiveNotification();

            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            _sut.MarkAsRead(42);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToNonDefault()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            _sut.Dispose();
            _sut.Dispose();
            // No exception expected
        }

        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdFallback()
        {
            _sut.SendNotification("Student", "5", "   ", EntityOperation.DELETE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student (ID: 5) has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithEmptyDisplayName_UsesIdFallback()
        {
            _sut.SendNotification("Student", "5", "", EntityOperation.UPDATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student (ID: 5) has been updated", notification.Message);
        }
    }
}

