using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        [DataRow(10, 1, 5, 2, DisplayName = "10 items, page 1, size 5 => 2 pages")]
        [DataRow(10, 2, 5, 2, DisplayName = "10 items, page 2, size 5 => 2 pages")]
        [DataRow(11, 1, 5, 3, DisplayName = "11 items, page 1, size 5 => 3 pages")]
        [DataRow(1, 1, 10, 1, DisplayName = "1 item, page 1, size 10 => 1 page")]
        [DataRow(0, 1, 10, 0, DisplayName = "0 items => 0 pages")]
        public void Constructor_SetsCorrectTotalPages(int count, int pageIndex, int pageSize, int expectedTotalPages)
        {
            var items = new List<int>();

            var sut = new PaginatedList<int>(items, count, pageIndex, pageSize);

            Assert.AreEqual(expectedTotalPages, sut.TotalPages);
            Assert.AreEqual(pageIndex, sut.PageIndex);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };

            var sut = new PaginatedList<string>(items, 10, 1, 3);

            Assert.AreEqual(3, sut.Count);
            CollectionAssert.AreEqual(items, sut);
        }

        [TestMethod]
        [DataRow(1, 3, false, DisplayName = "First page => no previous")]
        [DataRow(2, 3, true, DisplayName = "Second page => has previous")]
        [DataRow(3, 3, true, DisplayName = "Last page => has previous")]
        public void HasPreviousPage_ReturnsExpected(int pageIndex, int totalPages, bool expected)
        {
            var sut = new PaginatedList<int>(new List<int>(), totalPages * 5, pageIndex, 5);

            Assert.AreEqual(expected, sut.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 3, true, DisplayName = "First page of 3 => has next")]
        [DataRow(2, 3, true, DisplayName = "Middle page of 3 => has next")]
        [DataRow(3, 3, false, DisplayName = "Last page of 3 => no next")]
        [DataRow(1, 1, false, DisplayName = "Only page => no next")]
        public void HasNextPage_ReturnsExpected(int pageIndex, int totalPages, bool expected)
        {
            var sut = new PaginatedList<int>(new List<int>(), totalPages * 5, pageIndex, 5);

            Assert.AreEqual(expected, sut.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result.First());
            Assert.AreEqual(20, result.Last());
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result.First());
        }

        [TestMethod]
        public void Create_LastPartialPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(11, result.First());
            Assert.AreEqual(12, result.Last());
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
        }
    }
}
