using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    internal static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            return new SchoolContext(options);
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>()
            };
            var instructor2 = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };

            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            var dept1 = new Department
            {
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor1.ID
            };
            var dept2 = new Department
            {
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor2.ID
            };

            context.Departments.AddRange(dept1, dept2);
            context.SaveChanges();

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept1.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            var course2 = new Course
            {
                CourseID = 2021,
                Title = "Composition",
                Credits = 3,
                DepartmentID = dept2.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Courses.AddRange(course1, course2);
            context.SaveChanges();

            var student1 = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2010-09-01"),
                Enrollments = new List<Enrollment>()
            };
            var student2 = new Student
            {
                FirstMidName = "Meredith",
                LastName = "Alonso",
                EnrollmentDate = DateTime.Parse("2012-09-01"),
                Enrollments = new List<Enrollment>()
            };
            var student3 = new Student
            {
                FirstMidName = "Arturo",
                LastName = "Anand",
                EnrollmentDate = DateTime.Parse("2013-09-01"),
                Enrollments = new List<Enrollment>()
            };

            context.Students.AddRange(student1, student2, student3);
            context.SaveChanges();

            context.Enrollments.Add(new Enrollment
            {
                StudentID = student1.ID,
                CourseID = course1.CourseID,
                Grade = Grade.A
            });
            context.Enrollments.Add(new Enrollment
            {
                StudentID = student2.ID,
                CourseID = course2.CourseID,
                Grade = Grade.B
            });
            context.SaveChanges();

            // CourseAssignments
            context.CourseAssignments.Add(new CourseAssignment
            {
                CourseID = course1.CourseID,
                InstructorID = instructor1.ID
            });
            context.SaveChanges();
        }
    }
}

