using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain queue to avoid cross-test leakage from the static ConcurrentQueue
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            _sut.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Course", "101", EntityOperation.UPDATE, "System");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Course (ID: 101) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Department 'Math' has been created", DisplayName = "CREATE message")]
        [DataRow(EntityOperation.UPDATE, "Department 'Math' has been updated", DisplayName = "UPDATE message")]
        [DataRow(EntityOperation.DELETE, "Department 'Math' has been deleted", DisplayName = "DELETE message")]
        public void SendNotification_OperationTypes_GenerateCorrectMessages(EntityOperation operation, string expectedMessage)
        {
            _sut.SendNotification("Department", "1", "Math", operation, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();

            Assert.AreEqual("A", first.EntityType);
            Assert.AreEqual("B", second.EntityType);
            Assert.AreEqual("C", third.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_AfterReceived_QueueIsEmpty()
        {
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);
            _sut.ReceiveNotification();

            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            _sut.MarkAsRead(42);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToNonDefault()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            _sut.Dispose();
            _sut.Dispose();
            // No exception expected
        }

        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdFallback()
        {
            _sut.SendNotification("Student", "5", "   ", EntityOperation.DELETE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student (ID: 5) has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithEmptyDisplayName_UsesIdFallback()
        {
            _sut.SendNotification("Student", "5", "", EntityOperation.UPDATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student (ID: 5) has been updated", notification.Message);
        }
    }
}

