using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests : IDisposable
    {
        private SchoolContext _context;
        private StudentsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _sut = new StudentsController(_context);
            // Controller needs HttpContext for ViewBag/TempData
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            Dispose();
        }

        public void Dispose()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_DefaultSort_ReturnsViewWithStudentsOrderedByLastName()
        {
            var result = _sut.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.IsTrue(model.Count > 0);
            // Default sort is by LastName ascending
            var names = model.Select(s => s.LastName).ToList();
            CollectionAssert.AreEqual(names.OrderBy(n => n).ToList(), names);
        }

        [TestMethod]
        public void Index_NameDescSort_ReturnsStudentsOrderedByLastNameDescending()
        {
            var result = _sut.Index("name_desc", null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            var names = model.Select(s => s.LastName).ToList();
            CollectionAssert.AreEqual(names.OrderByDescending(n => n).ToList(), names);
        }

        [TestMethod]
        public void Index_DateSort_ReturnsStudentsOrderedByEnrollmentDate()
        {
            var result = _sut.Index("Date", null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            CollectionAssert.AreEqual(dates.OrderBy(d => d).ToList(), dates);
        }

        [TestMethod]
        public void Index_DateDescSort_ReturnsStudentsOrderedByEnrollmentDateDescending()
        {
            var result = _sut.Index("date_desc", null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            CollectionAssert.AreEqual(dates.OrderByDescending(d => d).ToList(), dates);
        }

        [TestMethod]
        public void Index_WithSearchString_FiltersStudents()
        {
            var result = _sut.Index(null, null, "Alexander", null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model.First().LastName);
        }

        [TestMethod]
        public void Index_WithSearchString_ResetsToPage1()
        {
            var result = _sut.Index(null, null, "A", 5) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_WithCurrentFilter_MaintainsFilter()
        {
            var result = _sut.Index(null, "Alexander", null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Details_WithValidId_ReturnsViewWithStudent()
        {
            var studentId = _context.Students.First().ID;

            var result = _sut.Details(studentId) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(studentId, model.ID);
        }

        [TestMethod]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2024-01-15")
            };

            var result = _sut.Create(student) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsTrue(_context.Students.Any(s => s.LastName == "Student"));
        }

        [TestMethod]
        public void Create_Post_MinDateEnrollment_ReturnsViewWithError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Bad",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_sut.ModelState.IsValid);
        }

        [TestMethod]
        public void Create_Post_DateBeforeSqlMinimum_ReturnsViewWithError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Bad",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ErrorCount > 0);
        }

        [TestMethod]
        public void Edit_Get_WithValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();

            var result = _sut.Edit(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        [TestMethod]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Edit(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _sut.Edit(99999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.AsNoTracking().First();
            student.LastName = "Updated";
            student.EnrollmentDate = DateTime.Parse("2024-06-01");

            var result = _sut.Edit(student) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_InvalidDate_ReturnsViewWithError()
        {
            var student = _context.Students.AsNoTracking().First();
            student.EnrollmentDate = DateTime.MinValue;

            var result = _sut.Edit(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_sut.ModelState.IsValid);
        }

        [TestMethod]
        public void Delete_Get_WithValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();

            var result = _sut.Delete(student.ID) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _sut.Delete(99999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            // Need TempData provider for this action
            _sut.TempData = new Microsoft.AspNetCore.Mvc.ViewFeatures.TempDataDictionary(
                _sut.ControllerContext.HttpContext,
                Moq.Mock.Of<Microsoft.AspNetCore.Mvc.ViewFeatures.ITempDataProvider>());

            var student = _context.Students.First();
            var id = student.ID;

            var result = _sut.DeleteConfirmed(id) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsFalse(_context.Students.Any(s => s.ID == id));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _sut.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2024-01-01")
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
        }
    }
}

