using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class DepartmentsControllerTests : IDisposable
    {
        private SchoolContext _context;
        private DepartmentsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _sut = new DepartmentsController(_context);
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            Dispose();
        }

        public void Dispose()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _sut.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<Department>;
            Assert.IsNotNull(model);
            Assert.IsTrue(model.Count >= 2);
        }

        [TestMethod]
        public void Details_WithValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();

            var result = _sut.Details(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.IsNotNull(model);
            Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
        }

        [TestMethod]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Details_WithInvalidId_ReturnsNotFound()
        {
            var result = _sut.Details(99999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Create_Get_ReturnsView()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2024-01-01"),
                InstructorID = _context.Instructors.First().ID
            };

            var result = _sut.Create(department) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsTrue(_context.Departments.Any(d => d.Name == "Physics"));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _sut.ModelState.AddModelError("Name", "Required");
            var department = new Department();

            var result = _sut.Create(department) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Get_WithValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();

            var result = _sut.Edit(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.IsNotNull(model);
            Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
        }

        [TestMethod]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
