using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests : IDisposable
    {
        private SchoolContext _context;
        private HomeController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _sut = new HomeController(_context);
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            Dispose();
        }

        public void Dispose()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            var result = _sut.Index() as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            var result = _sut.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            // Seeded data has students with different enrollment dates
            Assert.IsTrue(model.Count > 0);
        }

        [TestMethod]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            var result = _sut.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // Verify counts match actual student groupings
            var expectedGroups = _context.Students
                .GroupBy(s => s.EnrollmentDate)
                .Select(g => new { Date = g.Key, Count = g.Count() })
                .ToList();

            Assert.AreEqual(expectedGroups.Count, model.Count);
            foreach (var expected in expectedGroups)
            {
                Assert.IsTrue(model.Any(m =>
                    m.EnrollmentDate == expected.Date && m.StudentCount == expected.Count));
            }
        }

        [TestMethod]
        public void Contact_ReturnsViewWithMessage()
        {
            var result = _sut.Contact() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _sut.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsView()
        {
            var result = _sut.Error() as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _sut.Unauthorized() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _sut.ViewBag.Message);
        }
    }
}

