using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class CoursesControllerTests : IDisposable
    {
        private SchoolContext _context;
        private CoursesController _sut;
        private Mock<IWebHostEnvironment> _envMock;
        private Mock<ILogger<CoursesController>> _loggerMock;
        private string _tempDir;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _sut = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            Dispose();
        }

        public void Dispose()
        {
            _sut?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        [TestMethod]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _sut.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Course>;
            Assert.IsNotNull(model);
            Assert.IsTrue(model.Count >= 2);
        }

        [TestMethod]
        public void Details_WithValidId_ReturnsViewWithCourse()
        {
            var course = _context.Courses.First();

            var result = _sut.Details(course.CourseID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
            Assert.AreEqual(course.CourseID, model.CourseID);
        }

        [TestMethod]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Create_Get_ReturnsViewWithNewCourse()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
        }

        [TestMethod]
        public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var result = _sut.Create(course, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsTrue(_context.Courses.Any(c => c.CourseID == 9999));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _sut.ModelState.AddModelError("Title", "Required");
            var course = new Course();

            var result = _sut.Create(course, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Create_Post_InvalidImageExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.exe");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _sut.Create(course, fileMock.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_OversizedImage_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 8887,
                Title = "Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = _sut.Create(course, fileMock.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_ValidImage_UploadSucceeds()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "With Image",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("photo.jpg");
            fileMock.Setup(f => f.Length).Returns(1024);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _sut.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            var saved = _context.Courses.Find(7777);
            Assert.IsNotNull(saved);
            Assert.IsTrue(saved.TeachingMaterialImagePath.StartsWith("/Uploads/TeachingMaterials/"));
        }

        [TestMethod]
        public void Edit_Get_WithValidId_ReturnsViewWithCourse()
        {
            var course = _context.Courses.First();

            var result = _sut.Edit(course.CourseID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
            Assert.AreEqual(course.CourseID, model.CourseID);
        }

        [TestMethod]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Edit(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _sut.Edit(99999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            var course = _context.Courses.AsNoTracking().First();
            course.Title = "Updated Title";

            var result = _sut.Edit(course, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _sut.ModelState.AddModelError("Title", "Required");
            var course = new Course();

            var result = _sut.Edit(course, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Post_InvalidImageExtension_ReturnsViewWithError()
        {
            var course = _context.Courses.AsNoTracking().First();

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.pdf");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _sut.Edit(course, fileMock.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Delete_Get_WithValidId_ReturnsView()
        {
            var course = _context.Courses.First();

            var result = _sut.Delete(course.CourseID) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            var course = _context.Courses.First();
            var id = course.CourseID;

            var result = _sut.DeleteConfirmed(id) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsFalse(_context.Courses.Any(c => c.CourseID == id));
        }

        [TestMethod]
        [DataRow(".jpg", DisplayName = "JPG allowed")]
        [DataRow(".jpeg", DisplayName = "JPEG allowed")]
        [DataRow(".png", DisplayName = "PNG allowed")]
        [DataRow(".gif", DisplayName = "GIF allowed")]
        [DataRow(".bmp", DisplayName = "BMP allowed")]
        public void Create_Post_AllowedImageExtensions_Succeeds(string extension)
        {
            var course = new Course
            {
                CourseID = 5000 + Math.Abs(extension.GetHashCode() % 1000),
                Title = $"Course {extension}",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns($"test{extension}");
            fileMock.Setup(f => f.Length).Returns(1024);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _sut.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }
    }
}

