using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests : IDisposable
    {
        private SchoolContext _context;
        private InstructorsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _sut = new InstructorsController(_context);
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            Dispose();
        }

        public void Dispose()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithAllInstructors()
        {
            var result = _sut.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsTrue(model.Instructors.Any());
        }

        [TestMethod]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var instructor = _context.Instructors.First();

            var result = _sut.Index(instructor.ID, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Courses);
        }

        [TestMethod]
        public void Details_WithValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _sut.Details(instructor.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.AreEqual(instructor.ID, model.ID);
        }

        [TestMethod]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Details_WithInvalidId_ReturnsNotFound()
        {
            var result = _sut.Details(99999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Create_Get_ReturnsViewWithNewInstructor()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.CourseAssignments);
        }

        [TestMethod]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2024-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _sut.Create(instructor, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsTrue(_context.Instructors.Any(i => i.LastName == "Instructor"));
        }

        [TestMethod]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var courseId = _context.Courses.First().CourseID;
            var instructor = new Instructor
            {
                FirstMidName = "With",
                LastName = "Courses",
                HireDate = DateTime.Parse("2024-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _sut.Create(instructor, new[] { courseId.ToString() }) as RedirectToActionResult;

            Assert.IsNotNull(result);
            var saved = _context.Instructors.First(i => i.LastName == "Courses");
            // CourseAssignments are added during Create
            Assert.IsTrue(_context.CourseAssignments.Any(ca => ca.InstructorID == saved.ID));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _sut.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Bad",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _sut.Create(instructor, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Edit((int?)null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_WithValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _sut.Edit((int?)instructor.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.AreEqual(instructor.ID, model.ID);
        }

        [TestMethod]
        public void Delete_Get_WithValidId_ReturnsView()
        {
            var instructor = _context.Instructors.First();

            var result = _sut.Delete(instructor.ID) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _sut.Delete(99999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
        {
            // Add a fresh instructor that is not a department administrator
            var instructor = new Instructor
            {
                FirstMidName = "ToDelete",
                LastName = "Removable",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Temp Office"
            });
            _context.SaveChanges();
            var id = instructor.ID;

            var result = _sut.DeleteConfirmed(id) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsFalse(_context.Instructors.Any(i => i.ID == id));
        }

        [TestMethod]
        public void DeleteConfirmed_InstructorAsDeptAdmin_NullsOutDepartmentAdmin()
        {
            // Find an instructor that administers a department
            var dept = _context.Departments.First(d => d.InstructorID != null);
            var instructorId = dept.InstructorID.Value;

            // Ensure the instructor has an OfficeAssignment (required by the query)
            if (!_context.OfficeAssignments.Any(o => o.InstructorID == instructorId))
            {
                _context.OfficeAssignments.Add(new OfficeAssignment
                {
                    InstructorID = instructorId,
                    Location = "Test"
                });
                _context.SaveChanges();
            }

            _sut.DeleteConfirmed(instructorId);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.IsNull(updatedDept.InstructorID);
        }
    }
}

