using System;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests : IDisposable
    {
        private SchoolContext _context;
        private NotificationsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _sut = new NotificationsController(_context);
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };

            // Drain the static notification queue
            using var drainer = new NotificationService();
            while (drainer.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            Dispose();
        }

        public void Dispose()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _sut.GetNotifications();

            Assert.IsNotNull(result);
            var json = result.Value;
            Assert.IsNotNull(json);
            // Verify result has the success shape
            var successProp = json.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(json));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Send notifications via the shared service
            using var service = new NotificationService();
            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
            service.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");

            var result = _sut.GetNotifications();

            Assert.IsNotNull(result);
            var json = result.Value;
            var countProp = json.GetType().GetProperty("count");
            Assert.IsNotNull(countProp);
            var count = (int)countProp.GetValue(json);
            Assert.AreEqual(2, count);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _sut.MarkAsRead(1);

            Assert.IsNotNull(result);
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(json));
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            var result = _sut.Index() as ViewResult;

            Assert.IsNotNull(result);
        }
    }
}

