using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    [TestClass]
    public sealed class DbInitializerTests
    {
        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsAllEntityTypes()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.IsTrue(context.Students.Any(), "Students should be seeded");
            Assert.IsTrue(context.Instructors.Any(), "Instructors should be seeded");
            Assert.IsTrue(context.Departments.Any(), "Departments should be seeded");
            Assert.IsTrue(context.Courses.Any(), "Courses should be seeded");
            Assert.IsTrue(context.Enrollments.Any(), "Enrollments should be seeded");
            Assert.IsTrue(context.OfficeAssignments.Any(), "OfficeAssignments should be seeded");
            Assert.IsTrue(context.CourseAssignments.Any(), "CourseAssignments should be seeded");
        }

        [TestMethod]
        public void Initialize_ExpectedStudentCount()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(8, context.Students.Count());
        }

        [TestMethod]
        public void Initialize_ExpectedInstructorCount()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(5, context.Instructors.Count());
        }

        [TestMethod]
        public void Initialize_ExpectedDepartmentCount()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(4, context.Departments.Count());
        }

        [TestMethod]
        public void Initialize_ExpectedCourseCount()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_AlreadySeeded_DoesNotDuplicate()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);
            var firstStudentCount = context.Students.Count();

            DbInitializer.Initialize(context);
            var secondStudentCount = context.Students.Count();

            Assert.AreEqual(firstStudentCount, secondStudentCount);
        }

        [TestMethod]
        public void Initialize_SetsUpEnrollmentsWithGrades()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var gradedEnrollments = context.Enrollments.Where(e => e.Grade != null).ToList();
            Assert.IsTrue(gradedEnrollments.Count > 0);
            Assert.IsTrue(gradedEnrollments.Any(e => e.Grade == Grade.A));
            Assert.IsTrue(gradedEnrollments.Any(e => e.Grade == Grade.B));
        }

        [TestMethod]
        public void Initialize_SetsUpEnrollmentsWithNoGrade()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var ungradedEnrollments = context.Enrollments.Where(e => e.Grade == null).ToList();
            Assert.IsTrue(ungradedEnrollments.Count > 0);
        }

        [TestMethod]
        public void Initialize_SetsUpOfficeAssignments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(3, context.OfficeAssignments.Count());
        }

        [TestMethod]
        public void Initialize_DepartmentsHaveAdministrators()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var depts = context.Departments.ToList();
            Assert.IsTrue(depts.All(d => d.InstructorID.HasValue),
                "All departments should have an administrator");
        }
    }
}

